import React from "react";
import {
  Home,
  WishList,
  ProtectedRoute,
  AdminProtectedRoute,
  CartProtectedRoute,
  PageNotFound,
  ProductDetails,
  ProductByCategory,
  CheckoutPage,
} from "./shop";
import { DashboardAdmin, Categories, Products, Orders, HospitalDetails, EditProfile } from "./admin";
import AdminLogin from "./adminSuper/AdminLogin";
import AdminDashboard from "./adminSuper/AdminDashboard";
import Hospitals from "./adminSuper/Hospitals";
import Patients from "./adminSuper/Patients";
import Organs from "./adminSuper/Organs";
import CategoriesSuper from "./adminSuper/Categories";
import Analytics from "./adminSuper/Analytics";
import { AdminSuperProtectedRoute } from "./shop";
import { UserProfile, UserOrders, SettingUser, PhoneVerify } from "./shop/dashboardUser";
import ResetPassword from "./shop/auth/ResetPassword";

import { BrowserRouter as Router, Switch, Route } from "react-router-dom";

/* Routing All page will be here */
const Routes = (props) => {
  return (
    <Router>
      <Switch>
        {/* Shop & Public Routes */}
        <Route exact path="/" component={Home} />
        <Route exact path="/wish-list" component={WishList} />
        <Route exact path="/products/:id" component={ProductDetails} />
        <Route
          exact
          path="/products/category/:catId"
          component={ProductByCategory}
        />
        <CartProtectedRoute
          exact={true}
          path="/checkout"
          component={CheckoutPage}
        />
        <Route exact path="/reset-password/:resetToken" component={ResetPassword} />
        {/* Shop & Public Routes End */}

        {/* Admin Routes */}
        <AdminProtectedRoute
          exact={true}
          path="/admin/dashboard"
          component={DashboardAdmin}
        />
        <AdminProtectedRoute
          exact={true}
          path="/admin/dashboard/categories"
          component={Categories}
        />
        <AdminProtectedRoute
          exact={true}
          path="/admin/dashboard/products"
          component={Products}
        />
        <AdminProtectedRoute
          exact={true}
          path="/admin/dashboard/orders"
          component={Orders}
        />
        <AdminProtectedRoute
          exact={true}
          path="/admin/dashboard/hospital-details"
          component={HospitalDetails}
        />
        <AdminProtectedRoute
          exact={true}
          path="/admin/dashboard/edit-profile"
          component={EditProfile}
        />
        {/* Admin Routes End */}

        {/* Admin Super (Global Admin) Routes */}
        <Route exact path="/admin/login" component={AdminLogin} />
        <AdminSuperProtectedRoute exact={true} path="/admin" component={AdminDashboard} />
        <AdminSuperProtectedRoute exact={true} path="/admin/hospitals" component={Hospitals} />
        <AdminSuperProtectedRoute exact={true} path="/admin/patients" component={Patients} />
        <AdminSuperProtectedRoute exact={true} path="/admin/organs" component={Organs} />
        <AdminSuperProtectedRoute exact={true} path="/admin/categories" component={CategoriesSuper} />
        <AdminSuperProtectedRoute exact={true} path="/admin/analytics" component={Analytics} />
        {/* Admin Super Routes End */}

        {/* User Dashboard */}
        <ProtectedRoute
          exact={true}
          path="/user/profile"
          component={UserProfile}
        />
        <ProtectedRoute
          exact={true}
          path="/user/verify-phone"
          component={PhoneVerify}
        />
        <ProtectedRoute
          exact={true}
          path="/user/orders"
          component={UserOrders}
        />
        <ProtectedRoute
          exact={true}
          path="/user/setting"
          component={SettingUser}
        />
        {/* User Dashboard End */}

        {/* 404 Page */}
        <Route component={PageNotFound} />
      </Switch>
    </Router>
  );
};

export default Routes;
